import { useState, useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import { api, getAuthToken } from "../api";
import MedicineCard from "../components/MedicineCard";

const HIDDEN_NEARBY_RANGE_KM = 20;

function distanceInKm(lat1, lon1, lat2, lon2) {
  const toRad = (deg) => (deg * Math.PI) / 180;
  const R = 6371;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

export default function Search() {
  const [searchParams] = useSearchParams();
  const [query, setQuery] = useState("");
  const [meds, setMeds] = useState([]);
  const [allMatches, setAllMatches] = useState([]);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [userLocation, setUserLocation] = useState(null);

  useEffect(() => {
    const prefill = (searchParams.get("q") || "").trim();
    setQuery(prefill);
    search(1, prefill);
  }, [searchParams]);

  useEffect(() => {
    if (page > 1) {
      search(page);
    }
  }, [page]);

  useEffect(() => {
    if (!navigator.geolocation) {
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserLocation({
          latitude: position.coords.latitude,
          longitude: position.coords.longitude,
        });
      },
      () => {
        // Keep results visible even if location permission is denied.
      },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  }, []);

  const search = async (newPage = 1, forcedQuery = null) => {
    if (!getAuthToken()) {
      setError("Please login first.");
      setMeds([]);
      setAllMatches([]);
      return;
    }

    try {
      setError("");
      setMessage("");
      const activeQuery = (forcedQuery ?? query).trim();
      const params = { page: newPage };
      if (activeQuery) {
        params.q = activeQuery;
      }
      const res = await api.get("/medicines/", { params });

      const summaryRes = await api.get("/medicines/", {
        params: {
          q: activeQuery || undefined,
          page_size: 50,
        },
      });
      
      const medicines = res.data.results || res.data;
      const summaryMedicines = summaryRes.data.results || summaryRes.data;
      const total = res.data.count ? Math.ceil(res.data.count / 8) : 1;
      
      setMeds(medicines);
      setAllMatches(summaryMedicines);
      setTotalPages(total);
      setPage(newPage);
    } catch (err) {
      setError("Unable to fetch medicines. Please login and try again.");
      setMeds([]);
      setAllMatches([]);
    }
  };

  const addToCart = async (medicineId) => {
    try {
      setError("");
      await api.post("/cart/", { medicine: medicineId, quantity: 1 });
      setMessage("✓ Added to cart successfully!");
      setTimeout(() => setMessage(""), 3000);
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to add to cart.");
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    search(1);
  };

  const normalizedQuery = query.trim().toLowerCase();
  const medicineNamedMatches = normalizedQuery
    ? allMatches.filter((m) => (m.name || "").toLowerCase().includes(normalizedQuery))
    : allMatches;
  const uniqueShopIds = new Set(medicineNamedMatches.map((m) => m.shop));

  const medsWithDistance = meds.map((medicine) => {
    if (!userLocation || medicine.shop_latitude == null || medicine.shop_longitude == null) {
      return medicine;
    }

    const distanceKm = distanceInKm(
      userLocation.latitude,
      userLocation.longitude,
      Number(medicine.shop_latitude),
      Number(medicine.shop_longitude)
    );

    return { ...medicine, distanceKm };
  });

  const sortedMeds = [...medsWithDistance].sort((a, b) => {
    const aDistance = typeof a.distanceKm === "number" ? a.distanceKm : Number.POSITIVE_INFINITY;
    const bDistance = typeof b.distanceKm === "number" ? b.distanceKm : Number.POSITIVE_INFINITY;
    return aDistance - bDistance;
  });

  const visibleMeds = userLocation
    ? sortedMeds.filter((m) => typeof m.distanceKm === "number" && m.distanceKm <= HIDDEN_NEARBY_RANGE_KM)
    : sortedMeds;

  return (
    <div className="page">
      <section className="search-hero">
        <div className="page-header">
          <h1>🔍 Discover Medicines</h1>
          <p>Browse and order quality medicines</p>
        </div>

        <form onSubmit={handleSearch} className="search-container">
          <div className="search-box">
            <input
              type="text"
              placeholder="Search medicine, shop, area, or state"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              className="search-input"
            />
            <button type="submit" className="btn-search" aria-label="Search medicines">
              🔍
            </button>
          </div>
        </form>

      </section>

      {error && <div className="error-message">{error}</div>}
      {message && <div className="success-message">{message}</div>}

      {meds.length > 0 ? (
        <>
          <div className="results-info">
            Found {visibleMeds.length} medicine(s) • Page {page} of {totalPages}
          </div>

          <div className="results-info results-info-highlight">
            {uniqueShopIds.size} registered shop(s) have this medicine in current search results
            {userLocation ? ` within ${HIDDEN_NEARBY_RANGE_KM} km nearby coverage` : ""}
          </div>

          <div className="medicine-grid">
            {visibleMeds.map((m) => (
              <MedicineCard 
                key={m.id}
                medicine={m}
                onAddToCart={addToCart}
              />
            ))}
          </div>

          {visibleMeds.length === 0 && userLocation && (
            <div className="results-info results-info-highlight">
              No nearby registered shops found within {HIDDEN_NEARBY_RANGE_KM} km for this search.
            </div>
          )}

          {totalPages > 1 && (
            <div className="pagination-row">
              <button 
                onClick={() => search(page - 1)} 
                disabled={page === 1}
                className="btn-pagination"
              >
                ← Previous
              </button>
              
              <div className="pagination-info">
                Page {page} of {totalPages}
              </div>
              
              <button 
                onClick={() => search(page + 1)} 
                disabled={page === totalPages}
                className="btn-pagination"
              >
                Next →
              </button>
            </div>
          )}
        </>
      ) : (
        !error && (
          <div className="empty-state">
            <div className="empty-icon">💊</div>
            <h3>No medicines found</h3>
            <p>Try searching for different medicine names</p>
          </div>
        )
      )}
    </div>
  );
}
